### 2. 循环结构

#### 2.1 for 循环

```javascript
// 打印 0 到 9
for (let i = 0; i < 10; i++) {
    console.log(i);
}
```

#### 2.2 while 循环

```javascript
// 打印 0 到 9
let i = 0;
while (i < 10) {
    console.log(i);
    i++;
}
```

#### 2.3 do-while 循环

```javascript
// 打印 0 到 9
let i = 0;
do {
    console.log(i);
    i++;
} while (i < 10);
```

### 3. 函数

#### 3.1 函数定义

```javascript
function greet(name) {
    return "Hello, " + name + "!";
}
```

#### 3.2 箭头函数

```javascript
const greet = (name) => "Hello, " + name + "!";
```

### 4. 对象

#### 4.1 对象创建

```javascript
const person = {
    name: "Alice",
    age: 25,
    greet() {
        return "Hello, I'm " + this.name;
    }
};
```

#### 4.2 对象方法

```javascript
console.log(person.name); // Alice
console.log(person.greet()); // Hello, I'm Alice
```

### 5. 数组

#### 5.1 数组创建

```javascript
const numbers = [1, 2, 3, 4, 5];
```

#### 5.2 数组方法

```javascript
// map
const doubled = numbers.map(n => n * 2);
console.log(doubled); // [2, 4, 6, 8, 10]

// filter
const evens = numbers.filter(n => n % 2 === 0);
console.log(evens); // [2, 4]

// reduce
const sum = numbers.reduce((acc, n) => acc + n, 0);
console.log(sum); // 15
```

### 6. 类

#### 6.1 类定义

```javascript
class Animal {
    constructor(name) {
        this.name = name;
    }

    speak() {
        console.log(this.name + " makes a noise.");
    }
}
```

#### 6.2 类继承

```javascript
class Dog extends Animal {
    speak() {
        console.log(this.name + " barks.");
    }
}
```

### 7. 异步编程

#### 7.1 Promise

```javascript
const promise = new Promise((resolve, reject) => {
    setTimeout(() => {
        resolve("Done!");
    }, 1000);
});

promise.then(result => console.log(result));
```

#### 7.2 async/await

```javascript
async function fetchData() {
    const response = await fetch('https://api.example.com/data');
    const data = await response.json();
    return data;
}
```

### 8. 模块

#### 8.1 导出

```javascript
// math.js
export const add = (a, b) => a + b;
export const subtract = (a, b) => a - b;
```

#### 8.2 导入

```javascript
// main.js
import { add, subtract } from './math.js';
```

### 9. 错误处理

#### 9.1 try-catch

```javascript
try {
    // 可能抛出错误的代码
    const result = riskyOperation();
    console.log(result);
} catch (error) {
    console.error("Error:", error.message);
}
```

#### 9.2 throw

```javascript
function divide(a, b) {
    if (b === 0) {
        throw new Error("Division by zero");
    }
    return a / b;
}
```

### 10. 正则表达式

#### 10.1 创建正则表达式

```javascript
const regex = /abc/i; // 不区分大小写
const regex2 = new RegExp("abc", "i");
```

#### 10.2 正则表达式方法

```javascript
const str = "Hello World";
console.log(regex.test(str)); // true
console.log(str.match(regex)); // ["Hello"]
```

